     1|import { createGateway, generateText, streamText } from 'ai';
     2|import { acquireAIQueueSlot, classifyRequestLane, type IVXAIQueueLane } from './services/ivx-ai-queue';
     3|import { estimatePromptTokens, recordProviderTelemetry } from './services/ivx-provider-telemetry';
     4|import { attemptProviderFallback, classifyProviderFailure, isFailureRetryable } from './services/ivx-ai-provider-fallback';
     5|
     6|export type IVXAIModule = 'owner-room' | 'p0-ai-assistant' | 'p1-plan-creator' | 'public-chat' | string;
     7|export type IVXAIMessageRole = 'user' | 'assistant';
     8|
     9|export type IVXAITextMessage = {
    10|  role: IVXAIMessageRole;
    11|  content: string;
    12|};
    13|
    14|export type IVXAIImageAttachment = {
    15|  url: string;
    16|  mimeType?: string | null;
    17|};
    18|
    19|/**
    20| * A non-image binary attachment (PDF for OCR, video for understanding) passed to
    21| * a multimodal model as a `file` content part. `data` may be a URL, a base64
    22| * string, or raw bytes.
    23| */
    24|export type IVXAIFileAttachment = {
    25|  data: string | Uint8Array | ArrayBuffer;
    26|  mediaType: string;
    27|  filename?: string | null;
    28|};
    29|
    30|export type IVXAIProviderMetadata = {
    31|  provider: 'chatgpt';
    32|  source: 'remote_api';
    33|  model: string;
    34|  endpoint: string | null;
    35|  runtime: 'vercel_ai_gateway';
    36|  ivxAI: {
    37|    architecture: 'ivx-ai';
    38|    phase: 'agent_runtime_v2';
    39|    layer: 'ivx_ai_runtime_wrapper';
    40|    module: string;
    41|    providerDependency: 'chatgpt_current_baseline';
    42|    requestId: string | null;
    43|    generatedAt: string;
    44|  };
    45|};
    46|
    47|export type IVXAITextResult = {
    48|  text: string;
    49|  usage: unknown;
    50|  providerMetadata: IVXAIProviderMetadata;
    51|};
    52|
    53|type IVXAIGatewayFailureContext = {
    54|  module: string;
    55|  requestId: string | null;
    56|  model: string;
    57|  endpoint: string | null;
    58|  status?: number | null;
    59|  responseBody?: unknown;
    60|};
    61|
    62|export type IVXAIConfigurationSnapshot = {
    63|  configured: boolean;
    64|  hasGatewayUrl: boolean;
    65|  hasGatewayApiKey: boolean;
    66|  model: string;
    67|  endpoint: string | null;
    68|  runtime: 'vercel_ai_gateway';
    69|  layer: 'ivx_ai_runtime_wrapper';
    70|  phase: 'agent_runtime_v2';
    71|};
    72|
    73|const GATEWAY_BASE_PATH = '/v3/ai';
    74|// Full multimodal model billed against the paid Vercel AI Gateway balance.
    75|// gpt-4o-mini is a free-tier model that Vercel rate-limits and is the weakest
    76|// vision model; gpt-4o gives real image + document analysis with no free-tier
    77|// caps. Override with IVX_AI_MODEL / PUBLIC_CHAT_MODEL / OPENAI_MODEL if needed.
    78|const DEFAULT_IVX_AI_MODEL = readTrimmed(process.env.IVX_AI_MODEL) || 'openai/gpt-4o';
    79|
    80|// Adaptive timeout floor / ceiling. Short prompts resolve fast (floor), large
    81|// reports get more headroom (ceiling). Tuned so a 12k-token report has ~90s
    82|// to complete instead of dying at the legacy 8s wall.
    83|const IVX_AI_TIMEOUT_FLOOR_MS = (() => {
    84|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_MS) || '15000', 10);
    85|  return Number.isFinite(raw) && raw > 0 ? raw : 15_000;
    86|})();
    87|const IVX_AI_TIMEOUT_CEIL_MS = (() => {
    88|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_CEIL_MS) || '120000', 10);
    89|  return Number.isFinite(raw) && raw > 0 ? raw : 120_000;
    90|})();
    91|
    92|/**
    93| * Compute an adaptive hard timeout based on the size of the work.
    94| *
    95| * Budget heuristics:
    96| *  - Base latency: floor (covers handshake + first-token latency)
    97| *  - Output budget: ~50ms per maxOutputToken (gpt-4o-mini sustains ~20 tok/s)
    98| *  - Prompt budget: ~2ms per prompt char (covers large context ingestion)
    99| * Clamped to [floor, ceiling].
   100| */
   101|export function computeAdaptiveTimeoutMs(input: {
   102|  promptChars: number;
   103|  maxOutputTokens: number | null | undefined;
   104|}): number {
   105|  const outputBudget = (input.maxOutputTokens ?? 1500) * 50;
   106|  const promptBudget = input.promptChars * 2;
   107|  const budget = IVX_AI_TIMEOUT_FLOOR_MS + outputBudget + promptBudget;
   108|  return Math.min(IVX_AI_TIMEOUT_CEIL_MS, Math.max(IVX_AI_TIMEOUT_FLOOR_MS, budget));
   109|}
   110|
   111|function runWithHardTimeout<T>(label: string, promise: Promise<T>, timeoutMs: number): Promise<T> {
   112|  return new Promise<T>((resolve, reject) => {
   113|    const timer = setTimeout(() => {
   114|      const err = new Error(`${label} timed out after ${timeoutMs}ms`);
   115|      err.name = 'IVXAIGatewayTimeoutError';
   116|      reject(err);
   117|    }, timeoutMs);
   118|    promise.then(
   119|      (value) => {
   120|        clearTimeout(timer);
   121|        resolve(value);
   122|      },
   123|      (error) => {
   124|        clearTimeout(timer);
   125|        reject(error);
   126|      },
   127|    );
   128|  });
   129|}
   130|
   131|function readTrimmed(value: unknown): string {
   132|  return typeof value === 'string' ? value.trim() : '';
   133|}
   134|
   135|function nowIso(): string {
   136|  return new Date().toISOString();
   137|}
   138|
   139|// Backend MUST talk directly to the canonical Vercel AI Gateway so the paid
   140|// AI_GATEWAY_API_KEY bearer reaches Vercel intact. Any client-facing proxy
   141|// (EXPO_PUBLIC_IVX_AI_GATEWAY_URL, e.g. ai.ivxholding.com) is intended for
   142|// the frontend only and may strip the Authorization header, which causes the
   143|// gateway to fall back to anonymous free-tier rate limits and return the
   144|// "Free tier requests on this model are rate-limited" 429 even when the
   145|// account has paid balance. The server-only override IVX_AI_GATEWAY_URL is
   146|// honored for advanced routing; otherwise we go direct to Vercel.
   147|function getIVXAIGatewayRootUrl(): string {
   148|  return readTrimmed(process.env.IVX_AI_GATEWAY_URL)
   149|    || 'https://ai-gateway.vercel.sh';
   150|}
   151|
   152|function getIVXAIGatewayApiKey(): string {
   153|  return readTrimmed(process.env.AI_GATEWAY_API_KEY);
   154|}
   155|
   156|function buildGatewayBaseUrl(rootUrl: string): string | null {
   157|  const gatewayRootUrl = readTrimmed(rootUrl).replace(/\/+$/, '');
   158|  if (!gatewayRootUrl) {
   159|    return null;
   160|  }
   161|
   162|  if (gatewayRootUrl.endsWith('/v3/ai') || gatewayRootUrl.endsWith(GATEWAY_BASE_PATH)) {
   163|    return gatewayRootUrl;
   164|  }
   165|
   166|  return new URL(GATEWAY_BASE_PATH, `${gatewayRootUrl}/`).toString().replace(/\/+$/, '');
   167|}
   168|
   169|function getGatewayBaseUrl(): string | null {
   170|  return buildGatewayBaseUrl(getIVXAIGatewayRootUrl());
   171|}
   172|
   173|function getGatewayBaseUrlCandidates(): string[] {
   174|  const configured = getGatewayBaseUrl();
   175|  const canonical = buildGatewayBaseUrl('https://ai-gateway.vercel.sh');
   176|  // Always include the canonical Vercel gateway as a fallback candidate so a
   177|  // misconfigured IVX_AI_GATEWAY_URL cannot strand the backend on a proxy that
   178|  // strips auth headers (which causes free-tier 429s on a paid account).
   179|  const candidates = [configured, canonical];
   180|  return [...new Set(candidates.filter((candidate): candidate is string => Boolean(candidate)))];
   181|}
   182|
   183|function ensureIVXAIGatewayEnvironment(): void {
   184|  const apiKey = getIVXAIGatewayApiKey();
   185|  if (!apiKey) {
   186|    throw new Error('IVX AI runtime is not configured.');
   187|  }
   188|
   189|  if (!readTrimmed(process.env.AI_GATEWAY_API_KEY)) {
   190|    process.env.AI_GATEWAY_API_KEY = apiKey;
   191|  }
   192|}
   193|
   194|function readRecord(value: unknown): Record<string, unknown> {
   195|  return typeof value === 'object' && value !== null ? value as Record<string, unknown> : {};
   196|}
   197|
   198|function extractGatewayFailureContext(error: unknown): { status: number | null; responseBody: unknown } {
   199|  const record = readRecord(error);
   200|  const response = readRecord(record.response);
   201|  const cause = readRecord(record.cause);
   202|  const status = typeof record.statusCode === 'number'
   203|    ? record.statusCode
   204|    : typeof record.status === 'number'
   205|      ? record.status
   206|      : typeof record.responseStatus === 'number'
   207|        ? record.responseStatus
   208|        : typeof response.status === 'number'
   209|          ? response.status
   210|          : typeof cause.status === 'number'
   211|            ? cause.status
   212|            : null;
   213|  const responseBody = record.responseBody
   214|    ?? response.body
   215|    ?? response.data
   216|    ?? record.data
   217|    ?? record.body
   218|    ?? cause.responseBody
   219|    ?? cause.body
   220|    ?? null;
   221|  return { status, responseBody };
   222|}
   223|
   224|function normalizeGatewayFailure(error: unknown, context: IVXAIGatewayFailureContext): Error {
   225|  const message = error instanceof Error ? error.message : 'Gateway request failed';
   226|  const body = typeof context.responseBody === 'string'
   227|    ? context.responseBody.slice(0, 600)
   228|    : context.responseBody && typeof context.responseBody === 'object'
   229|      ? JSON.stringify(context.responseBody).slice(0, 600)
   230|      : null;
   231|  const detail = [
   232|    `IVX AI gateway request failed for ${context.module}.`,
   233|    `endpoint=${context.endpoint ?? 'unresolved'}`,
   234|    `model=${context.model}`,
   235|    context.status ? `status=${context.status}` : null,
   236|    `providerError=${message}`,
   237|    body ? `responseBody=${body}` : null,
   238|  ].filter(Boolean).join(' ');
   239|  const normalized = new Error(detail);
   240|  normalized.name = 'IVXAIGatewayRequestError';
   241|  return normalized;
   242|}
   243|
   244|function normalizeMessages(messages: IVXAITextMessage[] | undefined): IVXAITextMessage[] {
   245|  return (messages ?? [])
   246|    .map((message) => ({
   247|      role: message.role === 'assistant' ? 'assistant' as const : 'user' as const,
   248|      content: readTrimmed(message.content),
   249|    }))
   250|    .filter((message) => message.content.length > 0);
   251|}
   252|
   253|export function resolveIVXAIModel(explicitModel?: string | null, envCandidates: string[] = []): string {
   254|  const explicit = readTrimmed(explicitModel);
   255|  if (explicit) {
   256|    return explicit;
   257|  }
   258|
   259|  for (const envName of envCandidates) {
   260|    const candidate = readTrimmed(process.env[envName]);
   261|    if (candidate) {
   262|      return candidate;
   263|    }
   264|  }
   265|
   266|  return DEFAULT_IVX_AI_MODEL;
   267|}
   268|
   269|export function getIVXAIEndpoint(model: string = DEFAULT_IVX_AI_MODEL): string | null {
   270|  const baseUrl = getGatewayBaseUrl();
   271|  if (!baseUrl) {
   272|    return null;
   273|  }
   274|
   275|  return `${baseUrl}/${model}`;
   276|}
   277|
   278|export function isIVXAIConfigured(): boolean {
   279|  return getIVXAIGatewayRootUrl().length > 0 && getIVXAIGatewayApiKey().length > 0;
   280|}
   281|
   282|export function getIVXAIConfigurationSnapshot(model: string = DEFAULT_IVX_AI_MODEL): IVXAIConfigurationSnapshot {
   283|  const hasGatewayUrl = getIVXAIGatewayRootUrl().length > 0;
   284|  const hasGatewayApiKey = getIVXAIGatewayApiKey().length > 0;
   285|  return {
   286|    configured: hasGatewayUrl && hasGatewayApiKey,
   287|    hasGatewayUrl,
   288|    hasGatewayApiKey,
   289|    model,
   290|    endpoint: getIVXAIEndpoint(model),
   291|    runtime: 'vercel_ai_gateway',
   292|    layer: 'ivx_ai_runtime_wrapper',
   293|    phase: 'agent_runtime_v2',
   294|  };
   295|}
   296|
   297|export async function requestIVXAIText(input: {
   298|  module: IVXAIModule;
   299|  requestId?: string | null;
   300|  model?: string | null;
   301|  system?: string | null;
   302|  prompt?: string | null;
   303|  messages?: IVXAITextMessage[];
   304|  images?: IVXAIImageAttachment[];
   305|  files?: IVXAIFileAttachment[];
   306|  maxOutputTokens?: number;
   307|}): Promise<IVXAITextResult> {
   308|  const model = resolveIVXAIModel(input.model);
   309|  const endpoint = getIVXAIEndpoint(model);
   310|  const messages = normalizeMessages(input.messages);
   311|  const prompt = readTrimmed(input.prompt);
   312|  const system = readTrimmed(input.system);
   313|  const images = (input.images ?? [])
   314|    .map((img) => ({ url: readTrimmed(img.url), mimeType: readTrimmed(img.mimeType ?? '') || null }))
   315|    .filter((img) => img.url.length > 0);
   316|  const files = (input.files ?? []).filter(
   317|    (file) => readTrimmed(file.mediaType).length > 0 && file.data != null,
   318|  );
   319|
   320|  if (!prompt && messages.length === 0) {
   321|    throw new Error('IVX AI request requires a prompt or messages.');
   322|  }
   323|
   324|  const baseUrlCandidates = getGatewayBaseUrlCandidates();
   325|  if (baseUrlCandidates.length === 0) {
   326|    throw new Error('IVX AI runtime is not configured.');
   327|  }
   328|
   329|  console.log('[IVXAI] Routing request through IVX AI Phase 1 wrapper:', {
   330|    module: input.module,
   331|    requestId: input.requestId ?? null,
   332|    model,
   333|    endpoint,
   334|    baseUrlCandidates,
   335|    hasSystem: system.length > 0,
   336|    promptLength: prompt.length,
   337|    messageCount: messages.length,
   338|    authKeySource: 'AI_GATEWAY_API_KEY',
   339|    requestShape: messages.length > 0 ? 'messages' : 'prompt',
   340|    maxOutputTokens: input.maxOutputTokens ?? null,
   341|    phase: 'agent_runtime_v2',
   342|    layer: 'ivx_ai_runtime_wrapper',
   343|  });
   344|
   345|  // Adaptive timeout + queue gating: long prompts/reports get more time and a
   346|  // dedicated lane so they cannot block normal chat under contention.
   347|  const promptChars = prompt.length + system.length + messages.reduce((sum, m) => sum + m.content.length, 0);
   348|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   349|  const queueLane: IVXAIQueueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
   350|  const queueSlot = await acquireAIQueueSlot(queueLane);
   351|  const callStartedAt = Date.now();
   352|
   353|  let result: Awaited<ReturnType<typeof generateText>> | null = null;
   354|  let lastError: unknown = null;
   355|  let lastFailure: { status: number | null; responseBody: unknown } = { status: null, responseBody: null };
   356|  let successfulBaseUrl = baseUrlCandidates[0];
   357|  let retryCount = 0;
   358|
   359|  for (const baseURL of baseUrlCandidates) {
   360|    ensureIVXAIGatewayEnvironment();
   361|    try {
   362|      const gatewayProvider = createGateway({
   363|        apiKey: getIVXAIGatewayApiKey(),
   364|        baseURL,
   365|      });
   366|      const callTimeoutMs = adaptiveTimeoutMs;
   367|      if (images.length > 0 || files.length > 0) {
   368|        // Multimodal request: build a single user message with text + image/file
   369|        // parts so multimodal models (gpt-4o family for images/PDF OCR, video-
   370|        // capable models for video) can actually see the attachments.
   371|        const baseMessages = messages.length > 0
   372|          ? messages.slice(0, -1)
   373|          : [];
   374|        const lastTextMessage = messages.length > 0 ? messages[messages.length - 1] : null;
   375|        const userText = readTrimmed(
   376|          (lastTextMessage && lastTextMessage.role === 'user' ? lastTextMessage.content : '') || prompt
   377|        ) || 'Describe the attached file(s).';
   378|        const multimodalUser = {
   379|          role: 'user' as const,
   380|          content: [
   381|            { type: 'text' as const, text: userText },
   382|            ...images.map((img) => ({ type: 'image' as const, image: img.url })),
   383|            ...files.map((file) => ({ type: 'file' as const, data: file.data, mediaType: file.mediaType })),
   384|          ],
   385|        };
   386|        const finalMessages = lastTextMessage && lastTextMessage.role === 'user'
   387|          ? [...baseMessages, multimodalUser]
   388|          : [...messages, multimodalUser];
   389|        result = await runWithHardTimeout('IVX AI gateway (multimodal)', generateText({
   390|          model: gatewayProvider(model),
   391|          system: system.length > 0 ? system : undefined,
   392|          maxOutputTokens: input.maxOutputTokens,
   393|          // eslint-disable-next-line @typescript-eslint/no-explicit-any
   394|          messages: finalMessages as any,
   395|        }), callTimeoutMs);
   396|      } else {
   397|        result = messages.length > 0
   398|          ? await runWithHardTimeout('IVX AI gateway (messages)', generateText({
   399|              model: gatewayProvider(model),
   400|              system: system.length > 0 ? system : undefined,
   401|              maxOutputTokens: input.maxOutputTokens,
   402|              messages,
   403|            }), callTimeoutMs)
   404|          : await runWithHardTimeout('IVX AI gateway (prompt)', generateText({
   405|              model: gatewayProvider(model),
   406|              system: system.length > 0 ? system : undefined,
   407|              maxOutputTokens: input.maxOutputTokens,
   408|              prompt,
   409|            }), callTimeoutMs);
   410|      }
   411|      successfulBaseUrl = baseURL;
   412|      break;
   413|    } catch (error) {
   414|      retryCount += 1;
   415|      const failure = extractGatewayFailureContext(error);
   416|      lastError = error;
   417|      lastFailure = failure;
   418|      console.error('[IVXAI] Gateway request failed:', {
   419|        module: input.module,
   420|        requestId: input.requestId ?? null,
   421|        model,
   422|            endpoint: `${baseURL}/${model}`,
   423|        status: failure.status,
   424|        error: error instanceof Error ? error.message : 'Gateway request failed',
   425|        responseBodyType: typeof failure.responseBody,
   426|        responseBodyPreview: typeof failure.responseBody === 'string'
   427|          ? failure.responseBody.slice(0, 400)
   428|          : failure.responseBody && typeof failure.responseBody === 'object'
   429|            ? JSON.stringify(failure.responseBody).slice(0, 400)
   430|            : null,
   431|        errorName: error instanceof Error ? error.name : null,
   432|      });
   433|    }
   434|  }
   435|
   436|  if (!result) {
   437|    queueSlot.release();
   438|    const failureMessage = lastError instanceof Error ? lastError.message : 'Gateway request failed';
   439|    const isTimeout = lastError instanceof Error && lastError.name === 'IVXAIGatewayTimeoutError';
   440|
   441|    // Multi-provider fallback chain. Only invoked when:
   442|    //   - all primary gateway base URLs failed
   443|    //   - failure is in a retryable class (timeout / rate_limit / quota / 5xx / network)
   444|    //   - at least one fallback provider has its env key configured
   445|    // Fallbacks NEVER log API keys or prompt content.
   446|    const failureClass = classifyProviderFailure(lastError);
   447|    if (isFailureRetryable(failureClass)) {
   448|      const fallbackResult = await attemptProviderFallback({
   449|        module: String(input.module),
   450|        requestId: input.requestId ?? null,
   451|        system,
   452|        prompt,
   453|        messages,
   454|        maxOutputTokens: input.maxOutputTokens ?? null,
   455|        timeoutMs: adaptiveTimeoutMs,
   456|      });
   457|      if (fallbackResult) {
   458|        const fallbackMetadata: IVXAIProviderMetadata = {
   459|          provider: 'chatgpt',
   460|          source: 'remote_api',
   461|          model: fallbackResult.model,
   462|          endpoint: null,
   463|          runtime: 'vercel_ai_gateway',
   464|          ivxAI: {
   465|            architecture: 'ivx-ai',
   466|            phase: 'agent_runtime_v2',
   467|            layer: 'ivx_ai_runtime_wrapper',
   468|            module: input.module,
   469|            providerDependency: 'chatgpt_current_baseline',
   470|            requestId: input.requestId ?? null,
   471|            generatedAt: nowIso(),
   472|          },
   473|        };
   474|        recordProviderTelemetry({
   475|          traceId: input.requestId ?? null,
   476|          module: String(input.module),
   477|          model: fallbackResult.model,
   478|          endpoint: null,
   479|          promptChars,
   480|          promptTokensEstimated: estimatePromptTokens(promptChars),
   481|          completionTokens: null,
   482|          totalTokens: null,
   483|          latencyMs: Date.now() - callStartedAt,
   484|          retryCount: Math.max(0, retryCount - 1),
   485|          status: 'ok',
   486|          httpStatus: 200,
   487|          failureReason: `primary_failed_${failureClass}_fallback=${fallbackResult.provider}`,
   488|          maxOutputTokens: input.maxOutputTokens ?? null,
   489|          adaptiveTimeoutMs,
   490|          queueWaitMs: queueSlot.waitMs,
   491|        });
   492|        console.log('[IVXAI] Recovered via fallback provider:', {
   493|          module: input.module,
   494|          requestId: input.requestId ?? null,
   495|          primaryFailureClass: failureClass,
   496|          fallbackProvider: fallbackResult.provider,
   497|          fallbackModel: fallbackResult.model,
   498|        });
   499|        return {
   500|          text: fallbackResult.text,
   501|          usage: null,
   502|          providerMetadata: fallbackMetadata,
   503|        };
   504|      }
   505|    }
   506|
   507|    recordProviderTelemetry({
   508|      traceId: input.requestId ?? null,
   509|      module: String(input.module),
   510|      model,
   511|      endpoint,
   512|      promptChars,
   513|      promptTokensEstimated: estimatePromptTokens(promptChars),
   514|      completionTokens: null,
   515|      totalTokens: null,
   516|      latencyMs: Date.now() - callStartedAt,
   517|      retryCount: Math.max(0, retryCount - 1),
   518|      status: isTimeout ? 'timeout' : 'failed',
   519|      httpStatus: lastFailure.status,
   520|      failureReason: failureMessage,
   521|      maxOutputTokens: input.maxOutputTokens ?? null,
   522|      adaptiveTimeoutMs,
   523|      queueWaitMs: queueSlot.waitMs,
   524|    });
   525|    throw normalizeGatewayFailure(lastError, {
   526|      module: input.module,
   527|      requestId: input.requestId ?? null,
   528|      model,
   529|      endpoint,
   530|      status: lastFailure.status,
   531|      responseBody: lastFailure.responseBody,
   532|    });
   533|  }
   534|  queueSlot.release();
   535|
   536|  const text = readTrimmed(result.text);
   537|  if (!text) {
   538|    throw new Error('IVX AI runtime returned an empty response.');
   539|  }
   540|
   541|  const providerMetadata: IVXAIProviderMetadata = {
   542|    provider: 'chatgpt',
   543|    source: 'remote_api',
   544|    model,
   545|    endpoint: `${successfulBaseUrl}/${model}`,
   546|    runtime: 'vercel_ai_gateway',
   547|    ivxAI: {
   548|      architecture: 'ivx-ai',
   549|      phase: 'agent_runtime_v2',
